// newAuthSetupCmd prints concrete steps for getting a credential. Side-effect
// rule: print by default, --launch opt-in to open the URL, short-circuit when
// the verifier is running this in a sandboxed subprocess.
func newAuthSetupCmd(_ *rootFlags) *cobra.Command {
	var launch bool
	cmd := &cobra.Command{
		Use:     "setup",
		Short:   "Print steps for configuring a Goodreads browser session cookie (use --launch to open Goodreads)",
		Example: "  goodreads-pp-cli auth setup\n  goodreads-pp-cli auth setup --launch",
		RunE: func(cmd *cobra.Command, args []string) error {
			w := cmd.OutOrStdout()
			fmt.Fprintln(w, "Goodreads has no current public developer API key flow.")
			fmt.Fprintln(w, "Use an authenticated Goodreads browser session cookie for read-only personal/account pages.")
			fmt.Fprintln(w, "")
			fmt.Fprintln(w, "Set only the Goodreads _session_id2 cookie value:")
			fmt.Fprintln(w, "  goodreads-pp-cli auth set-token <_session_id2-cookie-value>")
			fmt.Fprintln(w, "  # or")
			fmt.Fprintln(w, "  export GOODREADS_GOODREADS_COOKIE_SESSION=<_session_id2-cookie-value>")
			fmt.Fprintln(w, "")
			fmt.Fprintln(w, "Do not paste broad Amazon, AWS, or unrelated browser cookies.")
			if !launch {
				return nil
			}
			launchURL := "https://www.goodreads.com"
			if cliutil.IsVerifyEnv() {
				fmt.Fprintf(w, "would launch: %s\n", launchURL)
				return nil
			}
			if err := openSetupURL(launchURL); err != nil {
				fmt.Fprintf(cmd.ErrOrStderr(), "could not open browser automatically: %v\nopen this URL manually: %s\n", err, launchURL)
			}
			return nil
		},
	}
	cmd.Flags().BoolVar(&launch, "launch", false, "Open the setup URL in your default browser")
	return cmd
}

// openSetupURL opens url in the OS default browser. Per the side-effect rule,
// the caller short-circuits with cliutil.IsVerifyEnv() before this is reached.
func openSetupURL(url string) error {
	var c *exec.Cmd
	switch runtime.GOOS {
	case "darwin":
		c = exec.Command("open", url)
	case "linux":
		c = exec.Command("xdg-open", url)
	case "windows":
		c = exec.Command("rundll32", "url.dll,FileProtocolHandler", url)
	default:
		return fmt.Errorf("unsupported OS: %s", runtime.GOOS)
	}
	return c.Start()
}

func newAuthStatusCmd(flags *rootFlags) *cobra.Command {
	return &cobra.Command{
		Use:     "status",
		Short:   "Show authentication status",
		Example: "  goodreads-pp-cli auth status",
		RunE: func(cmd *cobra.Command, args []string) error {
			cfg, err := config.Load(flags.configPath)
			if err != nil {
				return configErr(err)
			}

			w := cmd.OutOrStdout()
			header := cfg.AuthHeader()
			authed := header != ""
			// JSON envelope: {authenticated, verified, source, config}. When not
			// authenticated, write the envelope first then return authErr
			// so exit code carries the auth-failure signal.
			if flags.asJSON {
				out := map[string]any{
					"authenticated": authed,
					"verified":      false,
					"source":        cfg.AuthSource,
					"config":        cfg.Path,
				}
				if printErr := printJSONFiltered(w, out, flags); printErr != nil {
					return printErr
				}
				if !authed {
					return authErr(fmt.Errorf("no credentials configured"))
				}
				return nil
			}
			if !authed {
				fmt.Fprintln(w, red("Not authenticated"))
				fmt.Fprintln(w, "")
				fmt.Fprintln(w, "Set the Goodreads _session_id2 cookie value (pipe it to keep it out of shell history):")
				fmt.Fprintf(w, "  printf %%s \"$GOODREADS_SESSION\" | goodreads-pp-cli auth set-token\n")
				return authErr(fmt.Errorf("no credentials configured"))
			}

			fmt.Fprintln(w, green("Credentials present (not verified)"))
			fmt.Fprintf(w, "  Source: %s\n", cfg.AuthSource)
			fmt.Fprintf(w, "  Config: %s\n", cfg.Path)
			return nil
		},
	}
}

func newAuthSetTokenCmd(flags *rootFlags) *cobra.Command {
	return &cobra.Command{
		Use:   "set-token [token]",
		Short: "Save the Goodreads _session_id2 cookie value to the config file",
		// Prefer stdin: a token passed as a positional argument is written to
		// shell history (~/.bash_history, ~/.zsh_history) and is visible in the
		// process table (ps aux) while the command runs. Piping keeps the
		// session cookie out of both.
		Example: "  printf %s \"$GOODREADS_SESSION\" | goodreads-pp-cli auth set-token",
		Args:    cobra.MaximumNArgs(1),
		RunE: func(cmd *cobra.Command, args []string) error {
			var token string
			if len(args) == 1 {
				token = strings.TrimSpace(args[0])
			} else {
				data, rerr := io.ReadAll(cmd.InOrStdin())
				if rerr != nil {
					return usageErr(fmt.Errorf("reading token from stdin: %w", rerr))
				}
				token = strings.TrimSpace(string(data))
			}
			if token == "" {
				return usageErr(fmt.Errorf("no token provided: pipe it on stdin (recommended — keeps it out of shell history) or pass it as an argument"))
			}

			cfg, err := config.Load(flags.configPath)
			if err != nil {
				return configErr(err)
			}

			// Clear any legacy auth_header so AuthHeader() falls through to
			// the newly-saved credential. Without this, a pre-existing
			// auth_header value (common after regenerate) shadows the saved
			// token and set-token silently has no effect. Silent clear (no
			// log line): a masked-tail variant could leak token bytes through
			// scripted dogfood that captures stderr.
			cfg.AuthHeaderVal = ""
			// api_key auth: AuthHeader() reads the env-var-derived field, not
			// AccessToken. Writing the token to AccessToken via SaveTokens
			// would persist the bytes but leave doctor reporting "not
			// configured" — the slot the header builder consults stays empty.
			if err := cfg.SaveCredential(token); err != nil {
				return configErr(fmt.Errorf("saving token: %w", err))
			}

			// JSON envelope: {saved, config_path}.
			if flags.asJSON {
				return printJSONFiltered(cmd.OutOrStdout(), map[string]any{
					"saved":       true,
					"config_path": cfg.Path,
				}, flags)
			}
			fmt.Fprintf(cmd.OutOrStdout(), "Token saved to %s\n", cfg.Path)
			return nil
		},
	}
}

func newAuthLogoutCmd(flags *rootFlags) *cobra.Command {
	return &cobra.Command{
		Use:     "logout",
		Short:   "Clear stored credentials",
		Example: "  goodreads-pp-cli auth logout",
		RunE: func(cmd *cobra.Command, args []string) error {
			cfg, err := config.Load(flags.configPath)
			if err != nil {
				return configErr(err)
			}

			if err := cfg.ClearTokens(); err != nil {
				return configErr(fmt.Errorf("clearing tokens: %w", err))
			}

			// Identify which (if any) auth env vars are still exported so the
			// JSON envelope and the human prose can both surface them. Both the
			// session cookie and the GraphQL token are re-populated by
			// config.Load() from their env vars after logout (GraphQLToken keeps
			// `rating set/clear` working), so a still-exported value means the
			// user is not fully logged out.
			var envStillSet []string
			if os.Getenv("GOODREADS_GOODREADS_COOKIE_SESSION") != "" {
				envStillSet = append(envStillSet, "GOODREADS_GOODREADS_COOKIE_SESSION")
			}
			if os.Getenv("GOODREADS_GRAPHQL_TOKEN") != "" {
				envStillSet = append(envStillSet, "GOODREADS_GRAPHQL_TOKEN")
			}

			// JSON envelope: {cleared: true, note?: "<env_var> env var is still set"}.
			if flags.asJSON {
				out := map[string]any{"cleared": true}
				if len(envStillSet) > 0 {
					out["note"] = strings.Join(envStillSet, ", ") + " env var is still set"
				}
				return printJSONFiltered(cmd.OutOrStdout(), out, flags)
			}

			if len(envStillSet) > 0 {
				fmt.Fprintf(cmd.OutOrStdout(), "Config cleared. Note: %s env var is still set; unset it to fully log out.\n", strings.Join(envStillSet, ", "))
				return nil
			}
			fmt.Fprintln(cmd.OutOrStdout(), "Logged out. Credentials cleared.")
			return nil
		},
	}
}
